UPDATE /* @SQLID=SUB0202_0212-03_1#Sql002 */ T_JP_ORDER 
SET 
    SHUBETU = #{req.shubetu}
    , CODE = #{req.code}
    , MESSAGE = #{req.errMessage,typeHandler=com.sbibits.earth.dao.typehandler.StringTypeHandler}
    , UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    , UPDATE_USER = #{req.updateUser,typeHandler=com.sbibits.earth.dao.typehandler.StringTypeHandler}
    , ACCEPT_DATE = #{req.acceptDate}

        , ACCEPT_TIME = #{req.acceptTime}

WHERE
    IFA_ORDER_NO = TO_NUMBER(#{req.ifaOrderNo})
    AND IFA_ORDER_SUB_NO = TO_NUMBER(#{req.ifaOrderSubNo})
